'use client';

import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';
import { Badge } from '@/components/ui/badge';
import { User, Phone, Mail, MapPin, Calendar, Tag, History } from 'lucide-react';
import type { WhatsAppConversationWithRelations } from '@/types/whatsapp';

interface ContactSidebarProps {
    conversation: WhatsAppConversationWithRelations;
}

export function ContactSidebar({ conversation }: ContactSidebarProps) {
    // Extrair dados do contato (priorizando CRM, depois WhatsApp)
    const contactName = conversation.contact?.full_name || conversation.contact_name || conversation.phone_number;
    const contactPhone = conversation.contact?.phone || conversation.phone_number;
    const contactEmail = conversation.contact?.email || 'Sem email cadastrado';
    const initials = (contactName || 'Desconhecido')
        .split(' ')
        .map((n: string) => n[0])
        .join('')
        .slice(0, 2)
        .toUpperCase();

    return (
        <div className="flex flex-col h-full bg-muted/10">
            <div className="p-6 flex flex-col items-center border-b bg-background">
                <Avatar className="h-20 w-20 mb-4 border-2 border-muted">
                    <AvatarImage src={conversation.contact_profile_picture || ''} />
                    <AvatarFallback className="text-2xl">{initials}</AvatarFallback>
                </Avatar>
                <h3 className="text-lg font-semibold text-center">{contactName}</h3>
                <p className="text-sm text-muted-foreground">{contactPhone}</p>

                <div className="flex gap-2 mt-4">
                    <Button variant="outline" size="sm">
                        <User className="h-4 w-4 mr-2" />
                        Perfil CRM
                    </Button>
                </div>
            </div>

            <ScrollArea className="flex-1">
                <div className="p-6 space-y-6">
                    {/* Informações de Contato */}
                    <div className="space-y-3">
                        <h4 className="text-sm font-medium text-muted-foreground uppercase tracking-wider">
                            Informações
                        </h4>
                        <div className="space-y-2">
                            <div className="flex items-center gap-3 text-sm">
                                <Phone className="h-4 w-4 text-muted-foreground" />
                                <span>{contactPhone}</span>
                            </div>
                            <div className="flex items-center gap-3 text-sm">
                                <Mail className="h-4 w-4 text-muted-foreground" />
                                <span>{contactEmail}</span>
                            </div>
                            <div className="flex items-center gap-3 text-sm">
                                <MapPin className="h-4 w-4 text-muted-foreground" />
                                <span>Localização não disponível</span>
                            </div>
                        </div>
                    </div>

                    <Separator />

                    {/* Etiquetas */}
                    <div className="space-y-3">
                        <div className="flex justify-between items-center">
                            <h4 className="text-sm font-medium text-muted-foreground uppercase tracking-wider">
                                Etiquetas
                            </h4>
                            <Button variant="ghost" size="icon" className="h-6 w-6">
                                <Tag className="h-3 w-3" />
                            </Button>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {conversation.labels?.map((label) => (
                                <Badge
                                    key={label.id}
                                    variant="secondary"
                                    className="text-xs font-normal"
                                    style={{
                                        backgroundColor: `${label.color}20`,
                                        color: label.color,
                                    }}
                                >
                                    {label.name}
                                </Badge>
                            ))}
                            {(!conversation.labels || conversation.labels.length === 0) && (
                                <p className="text-xs text-muted-foreground italic">Sem etiquetas</p>
                            )}
                        </div>
                    </div>

                    <Separator />

                    {/* Histórico Recente */}
                    <div className="space-y-3">
                        <h4 className="text-sm font-medium text-muted-foreground uppercase tracking-wider">
                            Atividades Recentes
                        </h4>
                        <div className="space-y-3">
                            <div className="flex items-start gap-3 text-sm">
                                <div className="mt-0.5 bg-blue-100 dark:bg-blue-900 p-1 rounded-full">
                                    <History className="h-3 w-3 text-blue-600 dark:text-blue-400" />
                                </div>
                                <div>
                                    <p className="font-medium">Conversa Iniciada</p>
                                    <p className="text-xs text-muted-foreground">Hoje, 10:30</p>
                                </div>
                            </div>
                            {/* Mais itens mockados */}
                        </div>
                    </div>
                </div>
            </ScrollArea>
        </div>
    );
}
