'use client';

/**
 * Indicador de que a IA está processando uma resposta
 */

import { Bot } from 'lucide-react';
import { cn } from '@/lib/utils';

interface AITypingIndicatorProps {
    isVisible: boolean;
    startedAt?: string | null;
}

export function AITypingIndicator({ isVisible, startedAt }: AITypingIndicatorProps) {
    if (!isVisible) return null;

    return (
        <div className="flex gap-2 px-4 py-1 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <div className="w-8 flex-shrink-0" />
            <div className="flex items-center gap-2 px-3 py-2 bg-gradient-to-r from-purple-500/10 to-blue-500/10 border border-purple-500/20 rounded-2xl rounded-bl-md">
                <div className="relative">
                    <Bot className="h-4 w-4 text-purple-500" />
                    <span className="absolute -top-0.5 -right-0.5 h-2 w-2 bg-purple-500 rounded-full animate-ping" />
                </div>
                <div className="flex gap-1">
                    <span
                        className={cn(
                            'w-2 h-2 bg-purple-500 rounded-full animate-bounce'
                        )}
                        style={{ animationDelay: '0ms' }}
                    />
                    <span
                        className={cn(
                            'w-2 h-2 bg-purple-500 rounded-full animate-bounce'
                        )}
                        style={{ animationDelay: '150ms' }}
                    />
                    <span
                        className={cn(
                            'w-2 h-2 bg-purple-500 rounded-full animate-bounce'
                        )}
                        style={{ animationDelay: '300ms' }}
                    />
                </div>
                <span className="text-xs text-muted-foreground">IA analisando...</span>
            </div>
        </div>
    );
}
