'use client';

/**
 * Hook para gerenciar mensagens do WhatsApp
 * @module hooks/useWhatsAppMessages
 */

import { useMemo, useEffect } from 'react';
import { useMutation, useQueryClient, useInfiniteQuery } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useUserProfile } from '@/hooks/useUserProfile';
import { toast } from '@/hooks/use-toast';
import { WHATSAPP_CONVERSATIONS_KEY, WHATSAPP_INBOX_STATS_KEY } from './useWhatsAppConversations';
import { withQueryTimeout } from '@/lib/queryUtils';
import type {
    WhatsAppMessage,
    WhatsAppMessageWithRelations,
    WhatsAppMessageInsert,
    SendTextMessagePayload,
    SendMediaMessagePayload,
    SendTemplateMessagePayload,
} from '@/types/whatsapp';

// Query keys
export const WHATSAPP_MESSAGES_KEY = 'whatsapp-messages';

interface UseWhatsAppMessagesOptions {
    conversationId: string;
    limit?: number;
    enabled?: boolean;
}

export function useWhatsAppMessages(options: UseWhatsAppMessagesOptions) {
    const { conversationId, limit = 50, enabled = true } = options;
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user } = useAuth();
    const { profile } = useUserProfile();

    // =========================================
    // Query: Lista de mensagens (paginada)
    // =========================================
    const messagesQuery = useInfiniteQuery({
        queryKey: [WHATSAPP_MESSAGES_KEY, conversationId],
        queryFn: async ({ pageParam = 0 }): Promise<WhatsAppMessageWithRelations[]> => {
            return withQueryTimeout(async () => {
                if (!conversationId) return [];

                const { data, error } = await supabase
                    .from('whatsapp_messages')
                    .select(`
                        *,
                        media:whatsapp_media(*)
                    `)
                    .eq('conversation_id', conversationId)
                    .order('sent_at', { ascending: false })
                    .range(pageParam, pageParam + limit - 1);

                if (error) {
                    console.error('[useWhatsAppMessages] Error:', error);
                    throw error;
                }

                // Reverter ordem para exibição (mais antigas primeiro)
                return (data || []).reverse() as WhatsAppMessageWithRelations[];
            }, 15000);
        },
        getNextPageParam: (lastPage, allPages) => {
            if (lastPage.length < limit) return undefined;
            return allPages.flat().length;
        },
        initialPageParam: 0,
        enabled: enabled && !!conversationId,
        staleTime: Infinity,
        refetchOnWindowFocus: false,
    });

    // Flatten all pages into single array in chronological order
    const allMessages = useMemo(() => {
        if (!messagesQuery.data?.pages) return [];

        const flattened = [...messagesQuery.data.pages].reverse().flat();

        // Deduplicar por ID
        const seen = new Set<string>();
        return flattened.filter(msg => {
            if (seen.has(msg.id)) {
                return false;
            }
            seen.add(msg.id);
            return true;
        });
    }, [messagesQuery.data?.pages]);

    // =========================================
    // Mutation: Enviar mensagem de texto
    // =========================================
    const sendTextMutation = useMutation({
        mutationFn: async (payload: SendTextMessagePayload): Promise<WhatsAppMessage> => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            // Buscar dados da conversa
            const { data: convData, error: convError } = await supabase
                .from('whatsapp_conversations')
                .select('phone_number, user_id')
                .eq('id', payload.conversation_id)
                .single();

            const conversation = convData as { phone_number: string; user_id: string } | null;

            if (convError || !conversation) {
                console.error('[sendText] Conversation not found. Error:', convError);
                throw new Error(`Conversa não encontrada: ${convError?.message || 'desconhecido'}`);
            }

            // Criar mensagem no banco (status: sending)
            const messageData: WhatsAppMessageInsert = {
                user_id: conversation.user_id,
                organization_id: profile?.organization_id,
                conversation_id: payload.conversation_id,
                phone_number: conversation.phone_number,
                content: payload.content,
                direction: 'outbound',
                message_type: 'text',
                status: 'sent',
                sent_at: new Date().toISOString(),
                reply_to_message_id: payload.reply_to_message_id || null,
            };

            const { data: msgData, error: msgError } = await supabase
                .from('whatsapp_messages')
                .insert(messageData as never)
                .select()
                .single();

            const message = msgData as { id: string } | null;

            if (msgError || !message) throw msgError || new Error('Falha ao criar mensagem');

            // Chamar Edge Function para enviar via WhatsApp API
            const { error: sendError } = await supabase.functions.invoke('whatsapp-send-message', {
                body: {
                    message_id: message.id,
                    phone_number: conversation.phone_number,
                    content: payload.content,
                    reply_to_wa_id: payload.reply_to_message_id
                        ? await getWhatsAppMessageId(payload.reply_to_message_id)
                        : undefined,
                },
            });

            if (sendError) {
                await supabase
                    .from('whatsapp_messages')
                    .update({
                        status: 'failed',
                        error_message: sendError.message,
                    } as never)
                    .eq('id', message.id);

                throw sendError;
            }

            // Atualizar conversa
            await supabase
                .from('whatsapp_conversations')
                .update({
                    last_message_at: new Date().toISOString(),
                    last_message_preview: payload.content.substring(0, 100),
                    last_message_direction: 'outbound',
                    unread_count: 0,
                    updated_at: new Date().toISOString(),
                } as never)
                .eq('id', payload.conversation_id);

            return message as WhatsAppMessage;
        },
        onMutate: async (newTodo) => {
            await queryClient.cancelQueries({ queryKey: [WHATSAPP_MESSAGES_KEY, conversationId] });
            const previousMessages = queryClient.getQueryData([WHATSAPP_MESSAGES_KEY, conversationId]);

            const optimisticMessage: WhatsAppMessage = {
                id: `temp-${Date.now()}`,
                content: newTodo.content,
                direction: 'outbound',
                message_type: 'text',
                status: 'sending',
                sent_at: new Date().toISOString(),
                conversation_id: conversationId,
                user_id: user?.id || '',
                created_at: new Date().toISOString(),
                organization_id: profile?.organization_id || null,
                contact_id: null,
                lead_id: null,
                message_id: null,
                delivered_at: null,
                read_at: null,
                error_message: null,
                error_code: null,
                metadata: {},
                context: null,
                template_id: null,
                reply_to_message_id: null,
                phone_number: '', // Placeholder
            };

            queryClient.setQueryData(
                [WHATSAPP_MESSAGES_KEY, conversationId],
                (old: any) => {
                    if (!old || !old.pages) return old;
                    return {
                        ...old,
                        pages: [
                            [optimisticMessage, ...old.pages[0]],
                            ...old.pages.slice(1)
                        ]
                    };
                }
            );

            return { previousMessages };
        },
        onSuccess: () => {
            // No need to invalidate immediately if we trust subscription, 
            // but invalidation ensures consistency. We will keep it.
            // The real-time subscription will also trigger updates.
            // queryClient.invalidateQueries({ queryKey: [WHATSAPP_MESSAGES_KEY, conversationId] }); 
            // queryClient.invalidateQueries({ queryKey: [WHATSAPP_CONVERSATIONS_KEY] });
        },
        onError: (error, newTodo, context) => {
            if (context?.previousMessages) {
                queryClient.setQueryData([WHATSAPP_MESSAGES_KEY, conversationId], context.previousMessages);
            }
            toast({
                title: 'Erro ao enviar mensagem',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Enviar mídia
    // =========================================
    const sendMediaMutation = useMutation({
        mutationFn: async (payload: SendMediaMessagePayload): Promise<WhatsAppMessage> => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const { data: convData2, error: convError } = await supabase
                .from('whatsapp_conversations')
                .select('phone_number, user_id')
                .eq('id', payload.conversation_id)
                .single();

            const conversation = convData2 as { phone_number: string; user_id: string } | null;

            if (convError || !conversation) {
                throw new Error('Conversa não encontrada');
            }

            const { data: msgData2, error: msgError } = await supabase
                .from('whatsapp_messages')
                .insert({
                    user_id: conversation.user_id,
                    organization_id: profile?.organization_id,
                    conversation_id: payload.conversation_id,
                    phone_number: conversation.phone_number,
                    content: payload.caption || `[${payload.media_type}]`,
                    direction: 'outbound',
                    message_type: payload.media_type,
                    status: 'sent',
                    sent_at: new Date().toISOString(),
                    reply_to_message_id: payload.reply_to_message_id || null,
                } as never)
                .select()
                .single();

            const message = msgData2 as { id: string } | null;
            if (msgError || !message) throw msgError || new Error('Falha ao criar mensagem');

            // Salvar mídia
            await supabase.from('whatsapp_media').insert({
                message_id: message.id,
                media_type: payload.media_type,
                media_url: payload.media_url,
                file_name: payload.file_name || null,
            } as never);

            // Chamar Edge Function
            const { error: sendError } = await supabase.functions.invoke('whatsapp-send-message', {
                body: {
                    message_id: message.id,
                    phone_number: conversation.phone_number,
                    media_type: payload.media_type,
                    media_url: payload.media_url,
                    caption: payload.caption,
                },
            });

            if (sendError) {
                await supabase
                    .from('whatsapp_messages')
                    .update({
                        status: 'failed',
                        error_message: sendError.message,
                    } as never)
                    .eq('id', message.id);

                throw sendError;
            }

            // Atualizar conversa
            await supabase
                .from('whatsapp_conversations')
                .update({
                    last_message_at: new Date().toISOString(),
                    last_message_preview: payload.caption || `[${payload.media_type}]`,
                    last_message_direction: 'outbound',
                    unread_count: 0,
                    updated_at: new Date().toISOString(),
                } as never)
                .eq('id', payload.conversation_id);

            return message as WhatsAppMessage;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_MESSAGES_KEY, conversationId] });
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_CONVERSATIONS_KEY] });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao enviar mídia',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Enviar template
    // =========================================
    const sendTemplateMutation = useMutation({
        mutationFn: async (payload: SendTemplateMessagePayload): Promise<WhatsAppMessage> => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            // Buscar conversa
            const { data: convData3, error: convError3 } = await supabase
                .from('whatsapp_conversations')
                .select('phone_number, user_id')
                .eq('id', payload.conversation_id)
                .single();

            if (convError3 || !convData3) {
                throw new Error('Conversa não encontrada');
            }

            // Buscar template
            const { data: templateData, error: templateError } = await supabase
                .from('whatsapp_templates')
                .select('*')
                .eq('id', payload.template_id)
                .single();

            if (templateError || !templateData) {
                throw new Error('Template não encontrado');
            }

            const conversation = convData3 as { phone_number: string; user_id: string };
            const template = templateData as { name: string; language: string; components: any[] };

            // Montar preview do template
            let preview = template.name;
            const bodyComponent = (template.components as any[])?.find(c => c.type === 'BODY');
            if (bodyComponent?.text) {
                preview = bodyComponent.text;
                if (payload.template_variables) {
                    Object.entries(payload.template_variables).forEach(([key, value]) => {
                        preview = preview.replace(`{{${key}}}`, value);
                    });
                }
            }

            const { data: msgData3, error: msgError } = await supabase
                .from('whatsapp_messages')
                .insert({
                    user_id: conversation.user_id,
                    organization_id: profile?.organization_id,
                    conversation_id: payload.conversation_id,
                    phone_number: conversation.phone_number,
                    content: preview,
                    direction: 'outbound',
                    message_type: 'template',
                    status: 'sent',
                    sent_at: new Date().toISOString(),
                    template_id: payload.template_id,
                    metadata: {
                        template_name: template.name,
                        template_variables: payload.template_variables,
                    },
                } as never)
                .select()
                .single();

            const message = msgData3 as { id: string } | null;
            if (msgError || !message) throw msgError || new Error('Falha ao criar mensagem');

            const { error: sendError } = await supabase.functions.invoke('whatsapp-send-message', {
                body: {
                    message_id: message.id,
                    phone_number: conversation.phone_number,
                    template_name: template.name,
                    template_language: template.language,
                    template_variables: payload.template_variables,
                },
            });

            if (sendError) {
                await supabase
                    .from('whatsapp_messages')
                    .update({
                        status: 'failed',
                        error_message: sendError.message,
                    } as never)
                    .eq('id', message.id);

                throw sendError;
            }

            await supabase
                .from('whatsapp_conversations')
                .update({
                    last_message_at: new Date().toISOString(),
                    last_message_preview: preview.substring(0, 100),
                    last_message_direction: 'outbound',
                    unread_count: 0,
                    updated_at: new Date().toISOString(),
                } as never)
                .eq('id', payload.conversation_id);

            return message as WhatsAppMessage;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_MESSAGES_KEY, conversationId] });
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_CONVERSATIONS_KEY] });
            toast({
                title: 'Template enviado',
            });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao enviar template',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Helper: Buscar wa_id de uma mensagem
    // =========================================
    async function getWhatsAppMessageId(messageId: string): Promise<string | undefined> {
        const { data } = await supabase
            .from('whatsapp_messages')
            .select('message_id')
            .eq('id', messageId)
            .single();

        const result = data as { message_id: string | null } | null;
        return result?.message_id || undefined;
    }

    // =========================================
    // Helpers
    // =========================================
    const refetch = () => {
        queryClient.invalidateQueries({ queryKey: [WHATSAPP_MESSAGES_KEY, conversationId] });
    };

    const addOptimisticMessage = (content: string) => {
        queryClient.setQueryData(
            [WHATSAPP_MESSAGES_KEY, conversationId],
            (old: any) => {
                if (!old) return old;
                const optimisticMessage: Partial<WhatsAppMessage> = {
                    id: `temp-${Date.now()}`,
                    content,
                    direction: 'outbound',
                    message_type: 'text',
                    status: 'sent',
                    sent_at: new Date().toISOString(),
                    conversation_id: conversationId,
                };
                return {
                    ...old,
                    pages: [
                        ...old.pages.slice(0, -1),
                        [...(old.pages[old.pages.length - 1] || []), optimisticMessage],
                    ],
                };
            }
        );
    };

    // =========================================
    // Real-time Subscription
    // =========================================

    useEffect(() => {
        if (!enabled || !conversationId) return;

        console.log(`[useWhatsAppMessages] Subscribing to messages for conversation: ${conversationId}`);

        const channel = supabase
            .channel(`messages:${conversationId}`)
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'whatsapp_messages',
                    filter: `conversation_id=eq.${conversationId}`,
                },
                (payload) => {
                    console.log('[useWhatsAppMessages] New message received:', payload);
                    const newMessage = payload.new as WhatsAppMessage;

                    // Immediately add to cache if not already present (optimistic or real)
                    queryClient.setQueryData(
                        [WHATSAPP_MESSAGES_KEY, conversationId],
                        (old: any) => {
                            if (!old || !old.pages) return old;

                            // Check if message already exists (to avoid duplication if we added efficiently)
                            const exists = old.pages.some((page: any[]) =>
                                page.some((msg: WhatsAppMessage) => msg.id === newMessage.id)
                            );

                            if (exists) return old;

                            // Add to the first page (since pages are reversed later) or last page depending on structure
                            // Our queryFn returns reversed data, so typical infinite query structure depends on direction.
                            // But usually infinite query pages are ordered.
                            // Let's just refetch to be safe and consistent, OR append cautiously.
                            // Refeting is safer for complex infinite lists, but less "instant".
                            // Hybrid: Add to cache AND refetch.

                            return {
                                ...old,
                                pages: [
                                    [newMessage, ...old.pages[0]], // Prepend to first page (most recent)
                                    ...old.pages.slice(1)
                                ]
                            };
                        }
                    );

                    // Also refetch to get relations (media, etc) if needed, 
                    // though for text messages payload.new is usually enough.
                    // If it has media, we definitely need to refetch to get the join.
                    if (newMessage.message_type !== 'text') {
                        queryClient.invalidateQueries({ queryKey: [WHATSAPP_MESSAGES_KEY, conversationId] });
                    }
                }
            )
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'whatsapp_messages',
                    filter: `conversation_id=eq.${conversationId}`,
                },
                (payload) => {
                    console.log('[useWhatsAppMessages] Message updated:', payload);
                    const updatedMessage = payload.new as WhatsAppMessage;

                    queryClient.setQueryData(
                        [WHATSAPP_MESSAGES_KEY, conversationId],
                        (old: any) => {
                            if (!old || !old.pages) return old;

                            return {
                                ...old,
                                pages: old.pages.map((page: WhatsAppMessage[]) =>
                                    page.map(msg =>
                                        msg.id === updatedMessage.id
                                            ? { ...msg, ...updatedMessage }
                                            : msg
                                    )
                                )
                            };
                        }
                    );
                }
            )
            .subscribe();

        return () => {
            console.log(`[useWhatsAppMessages] Unsubscribing from ${conversationId}`);
            supabase.removeChannel(channel);
        };
    }, [conversationId, enabled, queryClient, supabase]);

    return {
        // Data
        messages: allMessages,
        isLoading: messagesQuery.isLoading,
        isFetchingNextPage: messagesQuery.isFetchingNextPage,
        hasNextPage: messagesQuery.hasNextPage,
        error: messagesQuery.error,

        // Pagination
        fetchNextPage: messagesQuery.fetchNextPage,

        // Mutations
        sendText: sendTextMutation.mutateAsync,
        isSendingText: sendTextMutation.isPending,

        sendMedia: sendMediaMutation.mutateAsync,
        isSendingMedia: sendMediaMutation.isPending,

        sendTemplate: sendTemplateMutation.mutateAsync,
        isSendingTemplate: sendTemplateMutation.isPending,

        isSending: sendTextMutation.isPending || sendMediaMutation.isPending || sendTemplateMutation.isPending,

        // Helpers
        refetch,
        addOptimisticMessage,
    };
}
