'use client';

import { useState, useCallback, useEffect } from 'react';
import { useSearchParams, useRouter, usePathname } from 'next/navigation';
import { WhatsAppLayout } from '@/components/whatsapp/WhatsAppLayout';
import { ConversationList } from '@/components/whatsapp/inbox/ConversationList';
import { ConversationFilters } from '@/components/whatsapp/inbox/ConversationFilters';
import { ChatWindow } from '@/components/whatsapp/chat/ChatWindow';
import { ContactSidebar } from '@/components/whatsapp/chat/ContactSidebar';
import { useWhatsAppConversations } from '@/hooks/useWhatsAppConversations';
import { WhatsAppConversationWithRelations } from '@/types/whatsapp';

export default function WhatsAppClient() {
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();

    // Filtros
    const [filters, setFilters] = useState<any>({
        status: 'all',
        assignedTo: 'all',
        ownerId: 'all',
        search: '',
    });

    // Estado da UI
    const [selectedConversationId, setSelectedConversationId] = useState<string | null>(null);
    const [showSidebar, setShowSidebar] = useState(false);

    // Sincronizar URL com seleção (opcional, bom para links diretos)
    useEffect(() => {
        const conversationId = searchParams.get('c');
        if (conversationId && conversationId !== selectedConversationId) {
            setSelectedConversationId(conversationId);
        }
    }, [searchParams, selectedConversationId]);

    // Hook de dados
    const {
        conversations,
        isLoading,
        refetch,
        isUpdating,
        markAsRead
    } = useWhatsAppConversations({
        filters,
        refetchInterval: 10000 // Polling a cada 10s
    });

    // Handlers
    const handleSelectConversation = useCallback((conversation: WhatsAppConversationWithRelations) => {
        setSelectedConversationId(conversation.id);

        // Atualizar URL sem recarregar
        const params = new URLSearchParams(searchParams);
        params.set('c', conversation.id);
        router.push(`${pathname}?${params.toString()}`);

        // Marcar como lida se necessário
        if (conversation.unread_count > 0) {
            markAsRead(conversation.id);
        }
    }, [pathname, router, searchParams, markAsRead]);

    const handleToggleSidebar = useCallback(() => {
        setShowSidebar(prev => !prev);
    }, []);

    const handleBackToInbox = useCallback(() => {
        setSelectedConversationId(null);
        const params = new URLSearchParams(searchParams);
        params.delete('c');
        router.push(`${pathname}?${params.toString()}`);
    }, [pathname, router, searchParams]);

    // Componentes para o Layout
    const selectedConversation = conversations.find(c => c.id === selectedConversationId);

    const InboxComponent = (
        <div className="flex flex-col h-full">
            <ConversationFilters
                filters={filters}
                onFiltersChange={(newFilters: any) => {
                    setFilters((prev: any) => ({ ...prev, ...newFilters }));
                }}
            />
            <ConversationList
                conversations={conversations}
                selectedId={selectedConversationId || undefined}
                onSelect={handleSelectConversation}
                isLoading={isLoading}
                onRefresh={refetch}
                isRefreshing={isLoading || isUpdating}
            />
        </div>
    );

    const ChatComponent = selectedConversation ? (
        <ChatWindow
            conversation={selectedConversation}
            onBack={handleBackToInbox}
            onToggleSidebar={handleToggleSidebar}
            showBackButton={!!selectedConversationId}
        />
    ) : null;

    // Sidebar com detalhes do contato
    const SidebarComponent = selectedConversation ? (
        <ContactSidebar conversation={selectedConversation} />
    ) : null;

    return (
        <WhatsAppLayout
            inbox={InboxComponent}
            chat={ChatComponent}
            sidebar={SidebarComponent}
            showSidebar={showSidebar}
            onToggleSidebar={handleToggleSidebar}
            selectedConversationId={selectedConversationId}
        />
    );
}
