'use client';

import { useState, useCallback, useRef } from 'react';
import {
    MoreVertical,
    Search,
    CheckCircle2,
    Clock,
    AlertOctagon,
    Tag,
    VolumeX,
    Volume2,
    ArrowLeft,
    ArrowUpCircle,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { MessageList } from './MessageList';
import { MessageInput, type MessageInputHandle } from './MessageInput';
import { useWhatsAppMessages } from '@/hooks/useWhatsAppMessages';
import { useWhatsAppConversations } from '@/hooks/useWhatsAppConversations';
import { CONVERSATION_STATUS_CONFIG } from '@/types/whatsapp';
import type {
    WhatsAppConversationWithRelations,
    WhatsAppMessageWithRelations,
    WhatsAppConversationStatus,
} from '@/types/whatsapp';

interface ChatWindowProps {
    conversation: WhatsAppConversationWithRelations;
    onBack?: () => void;
    onToggleSidebar?: () => void;
    showBackButton?: boolean;
}

export function ChatWindow({
    conversation,
    onBack,
    onToggleSidebar,
    showBackButton,
}: ChatWindowProps) {
    const [replyTo, setReplyTo] = useState<WhatsAppMessageWithRelations | null>(null);
    const messageInputRef = useRef<MessageInputHandle>(null);
    const [isDraggingGlobal, setIsDraggingGlobal] = useState(false);
    const dragCounter = useRef(0);

    // Messages
    const {
        messages,
        isLoading: isLoadingMessages,
        isFetchingNextPage,
        hasNextPage,
        fetchNextPage,
        sendText,
        isSending,
    } = useWhatsAppMessages({ conversationId: conversation.id });

    // Conversation actions
    const {
        changeStatus,
        isChangingStatus,
        toggleMute,
        isTogglingMute,
    } = useWhatsAppConversations();

    const displayName =
        conversation.contact_name ||
        conversation.contact?.full_name ||
        conversation.phone_number;
    const initials = displayName
        .split(' ')
        .map(n => n[0])
        .join('')
        .substring(0, 2)
        .toUpperCase();

    const statusConfig = CONVERSATION_STATUS_CONFIG[conversation.status];

    // Handlers
    const handleSendText = useCallback(
        async (text: string) => {
            await sendText({
                conversation_id: conversation.id,
                content: text,
                reply_to_message_id: replyTo?.id,
            });
            setReplyTo(null);
        },
        [sendText, replyTo, conversation.id]
    );

    const handleReply = useCallback((message: WhatsAppMessageWithRelations) => {
        setReplyTo(message);
        messageInputRef.current?.focus();
    }, []);

    const handleCancelReply = useCallback(() => {
        setReplyTo(null);
    }, []);

    const handleStatusChange = useCallback(
        async (status: WhatsAppConversationStatus) => {
            await changeStatus({
                conversationId: conversation.id,
                status,
            });
        },
        [changeStatus, conversation.id]
    );

    const handleToggleMute = useCallback(async () => {
        await toggleMute({
            conversationId: conversation.id,
            mute: !conversation.is_muted,
        });
    }, [toggleMute, conversation.id, conversation.is_muted]);

    // Drag and Drop Global
    const handleDragEnter = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        dragCounter.current++;
        setIsDraggingGlobal(true);
    }, []);

    const handleDragLeave = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        dragCounter.current--;
        if (dragCounter.current === 0) {
            setIsDraggingGlobal(false);
        }
    }, []);

    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
    }, []);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDraggingGlobal(false);
        dragCounter.current = 0;

        const text = e.dataTransfer.getData('text/plain');
        if (text) {
            messageInputRef.current?.appendText(text);
            return;
        }

        // Arquivos
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            const file = e.dataTransfer.files[0];
            console.log('Drop de arquivo detectado:', file.name);
        }
    }, []);

    return (
        <div className="flex h-full overflow-hidden">
            <div
                className="flex-1 flex flex-col h-full min-w-0 border-r relative"
                onDragEnter={handleDragEnter}
                onDragLeave={handleDragLeave}
                onDragOver={handleDragOver}
                onDrop={handleDrop}
            >
                {/* Global Drop Overlay */}
                {isDraggingGlobal && (
                    <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center bg-background/60 backdrop-blur-md animate-in fade-in duration-300">
                        <div className="p-8 rounded-3xl border-4 border-dashed border-primary bg-background/80 shadow-2xl flex flex-col items-center gap-4 scale-110 transition-transform">
                            <div className="w-20 h-20 rounded-full bg-primary/10 flex items-center justify-center">
                                <ArrowUpCircle className="h-10 w-10 text-primary animate-bounce" />
                            </div>
                            <div className="text-center">
                                <h3 className="text-xl font-bold text-foreground">Solte para enviar</h3>
                                <p className="text-muted-foreground text-sm">Documentos, imagens ou procedimentos</p>
                            </div>
                        </div>
                    </div>
                )}

                {/* Header */}
                <div className="flex items-center justify-between px-4 py-3 border-b bg-background">
                    <div className="flex items-center gap-3 min-w-0">
                        {/* Back button (mobile) */}
                        {showBackButton && (
                            <Button
                                variant="ghost"
                                size="icon"
                                className="flex-shrink-0 -ml-2 md:hidden"
                                onClick={onBack}
                            >
                                <ArrowLeft className="h-5 w-5" />
                            </Button>
                        )}

                        {/* Avatar */}
                        <Avatar
                            className="h-10 w-10 flex-shrink-0 cursor-pointer"
                            onClick={onToggleSidebar}
                        >
                            <AvatarImage
                                src={conversation.contact_profile_picture || undefined}
                            />
                            <AvatarFallback className="bg-green-500/10 text-green-600">
                                {initials}
                            </AvatarFallback>
                        </Avatar>

                        {/* Info */}
                        <div
                            className="min-w-0 cursor-pointer"
                            onClick={onToggleSidebar}
                        >
                            <div className="flex items-center gap-2">
                                <h2 className="font-medium truncate">{displayName}</h2>
                                {conversation.is_muted && (
                                    <VolumeX className="h-3 w-3 text-muted-foreground flex-shrink-0" />
                                )}
                            </div>
                            <div className="flex items-center gap-2">
                                <span className="text-xs text-muted-foreground truncate">
                                    {conversation.phone_number}
                                </span>
                                {statusConfig && (
                                    <Badge
                                        variant="secondary"
                                        className={cn('h-5 text-[10px]', statusConfig.color)}
                                    >
                                        {statusConfig.label}
                                    </Badge>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center gap-1">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="hidden md:flex"
                            onClick={onToggleSidebar}
                        >
                            <Search className="h-5 w-5" />
                        </Button>

                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="ghost" size="icon">
                                    <MoreVertical className="h-5 w-5" />
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end" className="w-48">
                                {/* Status changes */}
                                <DropdownMenuItem
                                    onClick={() => handleStatusChange('open')}
                                    disabled={conversation.status === 'open' || isChangingStatus}
                                >
                                    <CheckCircle2 className="h-4 w-4 mr-2 text-green-500" />
                                    Marcar como aberta
                                </DropdownMenuItem>
                                <DropdownMenuItem
                                    onClick={() => handleStatusChange('pending')}
                                    disabled={conversation.status === 'pending' || isChangingStatus}
                                >
                                    <Clock className="h-4 w-4 mr-2 text-yellow-500" />
                                    Marcar como pendente
                                </DropdownMenuItem>
                                <DropdownMenuItem
                                    onClick={() => handleStatusChange('resolved')}
                                    disabled={conversation.status === 'resolved' || isChangingStatus}
                                >
                                    <CheckCircle2 className="h-4 w-4 mr-2 text-blue-500" />
                                    Marcar como resolvida
                                </DropdownMenuItem>
                                <DropdownMenuItem
                                    onClick={() => handleStatusChange('spam')}
                                    disabled={conversation.status === 'spam' || isChangingStatus}
                                >
                                    <AlertOctagon className="h-4 w-4 mr-2 text-red-500" />
                                    Marcar como spam
                                </DropdownMenuItem>

                                <DropdownMenuSeparator />

                                {/* Other actions */}
                                <DropdownMenuItem
                                    onClick={handleToggleMute}
                                    disabled={isTogglingMute}
                                >
                                    {conversation.is_muted ? (
                                        <>
                                            <Volume2 className="h-4 w-4 mr-2" />
                                            Ativar notificações
                                        </>
                                    ) : (
                                        <>
                                            <VolumeX className="h-4 w-4 mr-2" />
                                            Silenciar
                                        </>
                                    )}
                                </DropdownMenuItem>

                                <DropdownMenuItem onClick={onToggleSidebar}>
                                    <Tag className="h-4 w-4 mr-2" />
                                    Ver detalhes
                                </DropdownMenuItem>
                            </DropdownMenuContent>
                        </DropdownMenu>
                    </div>
                </div>

                {/* Messages */}
                <div className="flex-1 flex flex-col overflow-hidden bg-muted/20">
                    <MessageList
                        key={conversation.id}
                        messages={messages}
                        isLoading={isLoadingMessages}
                        isFetchingMore={isFetchingNextPage}
                        hasMore={hasNextPage}
                        onLoadMore={fetchNextPage}
                        onReply={handleReply}
                    />
                </div>

                {/* Input */}
                <MessageInput
                    ref={messageInputRef}
                    onSendText={handleSendText}
                    replyTo={replyTo}
                    onCancelReply={handleCancelReply}
                    isSending={isSending}
                />
            </div>
        </div>
    );
}
